import type { WeightEntry } from '@motivation/shared';
import { HealthService } from '../../../services/health.service.js';
import { appTodayPlainDate, appTodayString, getAppTimeZone } from '../../../services/app-timezone.service.js';
import { buildSectionPage } from '../../../utils/section-page.utils.js';
import {
    createScreenStatusNodes,
    createScreenStatusMixin,
} from '../../_shared/screen-status.js';
import type { ScreenComponent } from '../../../types/screen-component.js';
import { createComponentLogger } from '../../../utils/component-logger.js';
import { documentStyleSheet } from '../../../utils/css.js';
import stylesText from './health-weight-screen.css?inline';

// Light-DOM section screen — adopt at document level (see documentStyleSheet).
documentStyleSheet(stylesText);

// How far back the history view reaches. A fixed bounded window keeps the fetch
// honest (no fetch-all) while covering a year of daily weigh-ins. Older history
// is out of scope for v1.
const HISTORY_WINDOW_DAYS = 365;

// Plausibility ceiling — mirrors the server-side validation in
// AbstractHealthRoutes.validateWeightKg. Above this (or ≤ 0) is a typo.
const MAX_WEIGHT_KG = 635;

const template = document.createElement('template');
template.innerHTML = `
    <section class="weight" data-testid="weight-section">
        <form class="weight__form" data-testid="weight-form">
            <div class="weight__fields">
                <input type="date" name="date" class="weight__date-input" data-testid="weight-date" required>
                <input type="number" name="weight_kg" class="weight__value-input" data-testid="weight-input"
                       step="0.1" min="0" inputmode="decimal" placeholder="kg" required>
                <input type="text" name="notes" class="weight__notes-input" data-testid="weight-notes" placeholder="note (optional)">
            </div>
            <div class="weight__actions">
                <button type="submit" class="weight__submit" data-testid="weight-submit">Log</button>
                <button type="button" class="weight__cancel" data-testid="weight-cancel" hidden>Cancel</button>
            </div>
            <p class="weight__form-error" data-testid="weight-form-error" hidden></p>
        </form>
        <p class="weight__empty" data-testid="weight-empty" hidden>No weigh-ins yet. Log your first above.</p>
        <ul class="weight__list" data-testid="weight-list"></ul>
    </section>
`;

/**
 * Story 170. Body-weight logging + history. A single form doubles as the
 * quick-add and (when a row's Edit is pressed) the edit form — keeping one
 * code path. The list reads newest-first from the server/offline replica.
 */
export class HealthWeightScreen extends HTMLElement implements ScreenComponent {
    private initialized = false;
    private status: ReturnType<typeof createScreenStatusMixin> | null = null;
    private statusNodes: ReturnType<typeof createScreenStatusNodes> | null = null;
    private form: HTMLFormElement | null = null;
    private dateInput: HTMLInputElement | null = null;
    private weightInput: HTMLInputElement | null = null;
    private notesInput: HTMLInputElement | null = null;
    private submitBtn: HTMLButtonElement | null = null;
    private cancelBtn: HTMLButtonElement | null = null;
    private formError: HTMLElement | null = null;
    private listEl: HTMLElement | null = null;
    private emptyEl: HTMLElement | null = null;
    private editingId: string | null = null;
    private readonly log = createComponentLogger('health-weight-screen');

    setLoading(): void {
        this.status?.setLoading();
    }
    setError(err: unknown): void {
        this.status?.setError(err);
    }
    clearStatus(): void {
        this.status?.clearStatus();
    }

    connectedCallback(): void {
        if (this.initialized) {
            void this.load();
            return;
        }
        this.initialized = true;

        const page = buildSectionPage(this, 'Weight', 'health', '/health');
        const fragment = template.content.cloneNode(true) as DocumentFragment;
        page.content.appendChild(fragment);

        this.form = page.content.querySelector<HTMLFormElement>('[data-testid="weight-form"]');
        this.dateInput = page.content.querySelector<HTMLInputElement>('[data-testid="weight-date"]');
        this.weightInput = page.content.querySelector<HTMLInputElement>('[data-testid="weight-input"]');
        this.notesInput = page.content.querySelector<HTMLInputElement>('[data-testid="weight-notes"]');
        this.submitBtn = page.content.querySelector<HTMLButtonElement>('[data-testid="weight-submit"]');
        this.cancelBtn = page.content.querySelector<HTMLButtonElement>('[data-testid="weight-cancel"]');
        this.formError = page.content.querySelector('[data-testid="weight-form-error"]');
        this.listEl = page.content.querySelector('[data-testid="weight-list"]');
        this.emptyEl = page.content.querySelector('[data-testid="weight-empty"]');

        this.statusNodes = createScreenStatusNodes();
        page.content.appendChild(this.statusNodes.loadingNode);
        page.content.appendChild(this.statusNodes.errorNode);
        page.content.appendChild(this.statusNodes.retryNode);
        this.status = createScreenStatusMixin(
            this.statusNodes.loadingNode,
            this.statusNodes.errorNode,
            this.statusNodes.retryNode,
        );

        this.statusNodes.retryNode.addEventListener('click', () => void this.load());
        this.form?.addEventListener('submit', (event) => {
            event.preventDefault();
            void this.submit();
        });
        this.cancelBtn?.addEventListener('click', () => this.resetForm());

        this.resetForm();
        void this.load();
    }

    private resetForm(): void {
        this.editingId = null;
        if (this.dateInput) this.dateInput.value = appTodayString();
        if (this.weightInput) this.weightInput.value = '';
        if (this.notesInput) this.notesInput.value = '';
        if (this.submitBtn) this.submitBtn.textContent = 'Log';
        if (this.cancelBtn) this.cancelBtn.hidden = true;
        this.clearFormError();
    }

    private clearFormError(): void {
        if (this.formError) {
            this.formError.hidden = true;
            this.formError.textContent = '';
        }
    }

    private showFormError(message: string): void {
        if (this.formError) {
            this.formError.hidden = false;
            this.formError.textContent = message;
        }
    }

    private async submit(): Promise<void> {
        this.clearFormError();
        const date = this.dateInput?.value ?? '';
        const rawWeight = this.weightInput?.value ?? '';
        const notes = this.notesInput?.value.trim() ?? '';

        if (!date) {
            this.showFormError('Pick a date.');
            return;
        }
        const weight_kg = Number.parseFloat(rawWeight);
        if (!Number.isFinite(weight_kg) || weight_kg <= 0) {
            this.showFormError('Enter a weight greater than 0.');
            return;
        }
        if (weight_kg > MAX_WEIGHT_KG) {
            this.showFormError(`Weight must be at most ${MAX_WEIGHT_KG} kg.`);
            return;
        }

        const payload = { date, weight_kg, notes: notes || undefined };
        try {
            if (this.editingId) {
                await HealthService.updateWeightEntry(this.editingId, payload);
            } else {
                await HealthService.createWeightEntry(payload);
            }
            this.resetForm();
            await this.load();
        } catch (err) {
            this.log.error('weight save failed:', err);
            this.setError(err);
        }
    }

    private beginEdit(entry: WeightEntry): void {
        this.editingId = entry.id;
        if (this.dateInput) this.dateInput.value = entry.date;
        if (this.weightInput) this.weightInput.value = String(entry.weight_kg);
        if (this.notesInput) this.notesInput.value = entry.notes ?? '';
        if (this.submitBtn) this.submitBtn.textContent = 'Update';
        if (this.cancelBtn) this.cancelBtn.hidden = false;
        this.clearFormError();
        this.weightInput?.focus();
    }

    private async removeEntry(id: string): Promise<void> {
        try {
            await HealthService.deleteWeightEntry(id);
            // If the row being edited was deleted, drop back to add mode.
            if (this.editingId === id) this.resetForm();
            await this.load();
        } catch (err) {
            this.log.error('weight delete failed:', err);
            this.setError(err);
        }
    }

    // SQLite `datetime('now')` yields "YYYY-MM-DD HH:MM:SS" (UTC, no tz marker);
    // coaching's generated_at is a full ISO instant. Normalize either into a
    // local HH:MM, falling back to empty when it can't be parsed (fail soft on a
    // cosmetic label, not on the data).
    private formatTime(createdAt: string): string {
        try {
            const normalized = createdAt.includes('T') ? createdAt : createdAt.replace(' ', 'T');
            const withZone = /[zZ]|[+-]\d\d:?\d\d$/.test(normalized) ? normalized : `${normalized}Z`;
            const zoned = Temporal.Instant.from(withZone).toZonedDateTimeISO(getAppTimeZone());
            return zoned.toPlainTime().toString({ smallestUnit: 'minute' });
        } catch {
            return '';
        }
    }

    private renderList(entries: WeightEntry[]): void {
        if (!this.listEl || !this.emptyEl) return;
        this.listEl.replaceChildren();
        this.emptyEl.hidden = entries.length > 0;

        for (const entry of entries) {
            const li = document.createElement('li');
            li.className = 'weight__row';
            li.dataset.testid = 'weight-row';
            li.dataset.id = entry.id;

            const date = document.createElement('span');
            date.className = 'weight__row-date';
            date.textContent = entry.date;

            const time = document.createElement('span');
            time.className = 'weight__row-time';
            time.textContent = this.formatTime(entry.created_at);

            const value = document.createElement('span');
            value.className = 'weight__row-value';
            value.textContent = `${entry.weight_kg} kg`;

            li.append(date, time, value);

            if (entry.notes) {
                const note = document.createElement('span');
                note.className = 'weight__row-note';
                note.textContent = entry.notes;
                li.appendChild(note);
            }

            const editBtn = document.createElement('button');
            editBtn.type = 'button';
            editBtn.className = 'weight__row-edit';
            editBtn.dataset.testid = 'weight-edit';
            editBtn.textContent = 'Edit';
            editBtn.addEventListener('click', () => this.beginEdit(entry));

            const deleteBtn = document.createElement('button');
            deleteBtn.type = 'button';
            deleteBtn.className = 'weight__row-delete';
            deleteBtn.dataset.testid = 'weight-delete';
            deleteBtn.textContent = 'Delete';
            deleteBtn.addEventListener('click', () => void this.removeEntry(entry.id));

            li.append(editBtn, deleteBtn);
            this.listEl.appendChild(li);
        }
    }

    private async load(): Promise<void> {
        this.setLoading();
        try {
            const to = appTodayString();
            const from = appTodayPlainDate().subtract({ days: HISTORY_WINDOW_DAYS }).toString();
            const entries = await HealthService.fetchWeightByDateRange(from, to);
            this.renderList(entries);
            this.clearStatus();
        } catch (err) {
            this.log.error('fetchWeightByDateRange failed:', err);
            this.setError(err);
        }
    }
}

if (!customElements.get('health-weight-screen')) {
    customElements.define('health-weight-screen', HealthWeightScreen);
}
